import React, { useState, useEffect } from "react";
import DualGauge from "./components/DualGauge"; // Объединенный компонент
import Speedometer from "./components/Speedometer";
import Tachometer from "./components/Tachometer";
import StartEngine from "./components/StartEngine";
const Dashboard = () => {
    const [engineStarted, setEngineStarted] = useState(false);
    const [progress, setProgress] = useState(0); // Прогресс движения шкалы от 0 до 1
    const initialValues = {
        fuelLevel: 0.56, // Уровень топлива в долях от 0 до 1
        temperature: 92, // Текущая температура
        speed: 0,
        rpm: 0,
    };
    const maxValues = {
        fuelLevel: 1, // Максимальный уровень топлива (1 соответствует 100%)
        temperature: 130, // Максимальная температура
        speed: 200,
        rpm: 8000,
    };
    const calculateValues = (progress) => ({
        fuelLevel: maxValues.fuelLevel -
            (maxValues.fuelLevel - initialValues.fuelLevel) * progress,
        temperature: maxValues.temperature -
            (maxValues.temperature - initialValues.temperature) * progress,
        speed: maxValues.speed * (1 - progress),
        rpm: maxValues.rpm * (1 - progress),
    });
    useEffect(() => {
        if (engineStarted) {
            const duration = 1000; // Длительность в миллисекундах
            const steps = 60; // Количество кадров
            const interval = duration / steps;
            let currentStep = 0;
            const timer = setInterval(() => {
                currentStep++;
                const newProgress = currentStep / steps; // Прогресс от 0 до 1
                setProgress(newProgress);
                if (currentStep >= steps) {
                    clearInterval(timer);
                }
            }, interval);
            return () => clearInterval(timer);
        }
    }, [engineStarted]);
    const currentValues = calculateValues(progress);
    return (React.createElement("div", { className: "h-screen bg-gray-900 flex justify-center items-center" },
        React.createElement("div", { className: "dashboard-frame relative flex flex-col items-center" },
            React.createElement("div", { className: "absolute top-4 right-4" },
                React.createElement(StartEngine, { isStarted: engineStarted, onToggle: (state) => setEngineStarted(state) })),
            React.createElement("div", { className: "flex justify-between items-center w-full px-16" },
                React.createElement("div", { className: "flex flex-col items-center" },
                    React.createElement(Tachometer, { rpm: currentValues.rpm, maxRpm: 8000 })),
                React.createElement("div", { className: "flex justify-center items-center" },
                    React.createElement(Speedometer, { speed: currentValues.speed, maxSpeed: 200 })),
                React.createElement("div", { className: "flex flex-col items-center" },
                    React.createElement(DualGauge, { temperature: currentValues.temperature, maxTemperature: 130, fuelLevel: currentValues.fuelLevel, maxFuelLevel: 1 }))))));
};
export default Dashboard;
